     9→// ─── Core fetch helper ────────────────────────────────────────────────────────
    10→
    11→async function apiFetch<T>(path: string, options?: RequestInit): Promise<T> {
    12→  const token = getToken();
    13→  const res = await fetch(`${API_BASE}${path}`, {
    14→    ...options,
    15→    headers: {
    16→      'Content-Type': 'application/json',
    17→      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    18→      ...options?.headers,
    19→    },
    20→  });
    21→  if (!res.ok) {
    22→    const err = await res.json().catch(() => ({ message: res.statusText }));
    23→    throw new Error(err.message || 'Request failed');
    24→  }
    25→  return res.json();
    26→}
    27→
    28→async function fetchAll<T>(endpoint: string): Promise<T[]> {
    29→  return apiFetch<T[]>(`/${endpoint}`);
    30→}
    31→
    32→async function insertRow<T>(endpoint: string, row: Row): Promise<T> {
    33→  return apiFetch<T>(`/${endpoint}`, { method: 'POST', body: JSON.stringify(row) });
    34→}
    35→
    36→async function updateRow<T>(endpoint: string, id: string, data: Row): Promise<T> {
    37→  return apiFetch<T>(`/${endpoint}/${id}`, { method: 'PUT', body: JSON.stringify(data) });
    38→}
    39→
    40→async function deleteRow(endpoint: string, id: string): Promise<void> {
    41→  await apiFetch(`/${endpoint}/${id}`, { method: 'DELETE' });
    42→}
