   405→                <input type="date" value={form.due_date} onChange={e => setForm(p => ({ ...p, due_date: e.target.value }))}
   406→                  className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-emerald-500" />
   407→              </div>
   408→              <div className="col-span-2 flex gap-3 pt-2">
   409→                <button type="button" onClick={() => setShowModal(false)}
   410→                  className="flex-1 rounded-xl bg-gray-800 py-2.5 text-sm font-medium text-gray-300 hover:bg-gray-700">Cancel</button>
   411→                <button type="button" className="p-2.5 rounded-xl bg-gray-800 text-gray-400 hover:text-white" title="Download PDF">
   412→                  <Download className="w-4 h-4" />
   413→                </button>
   414→                <button type="submit" disabled={createMutation.isPending || updateMutation.isPending}
   415→                  className="flex-1 rounded-xl bg-emerald-600 py-2.5 text-sm font-semibold text-white hover:bg-emerald-500 disabled:opacity-50 flex items-center justify-center gap-2">
   416→                  {(createMutation.isPending || updateMutation.isPending) && <Loader2 className="w-4 h-4 animate-spin" />}
   417→                  {editId ? 'Save Changes' : 'Create Invoice'}
   418→                </button>
   419→              </div>
   420→            </form>
   421→          </div>
   422→        </div>
   423→      )}
   424→
   425→      {/* Detail panel */}
   426→      {selectedInv && !showModal && (
   427→        <div className="fixed inset-0 z-40 flex" onClick={() => setSelectedId(null)}>
   428→          <div className="flex-1" />
   429→          <div className="w-full max-w-sm bg-gray-900 border-l border-gray-700 p-6 overflow-y-auto shadow-2xl"
