   434→            </div>
   435→            <div className="space-y-3 text-sm">
   436→              {[
   437→                ['Client', (selectedInv as Record<string,unknown>).client],
   438→                ['Description', (selectedInv as Record<string,unknown>).description],
   439→                ['Amount', fmt(Number((selectedInv as Record<string,unknown>).amount))],
   440→                ['VAT', fmt(Number((selectedInv as Record<string,unknown>).vat))],
   441→                ['CIS Deduction', `-${fmt(Number((selectedInv as Record<string,unknown>).cis_deduction ?? (selectedInv as Record<string,unknown>).cisDeduction ?? 0))}`],
   442→                ['Status', statusConfig[String((selectedInv as Record<string,unknown>).status)]?.label],
   443→                ['Due Date', (selectedInv as Record<string,unknown>).due_date ?? (selectedInv as Record<string,unknown>).dueDate],
   444→              ].map(([k, v]) => (
   445→                <div key={String(k)} className="flex justify-between border-b border-gray-800 pb-2">
   446→                  <span className="text-gray-400">{String(k)}</span>
   447→                  <span className="text-white font-medium text-right ml-4">{String(v ?? '—')}</span>
   448→                </div>
   449→              ))}
   450→            </div>
   451→            <div className="flex gap-2 mt-6">
   452→              <button onClick={() => openEdit(selectedInv as Record<string, unknown>)}
   453→                className="flex-1 rounded-xl bg-blue-600 py-2.5 text-sm font-semibold text-white hover:bg-blue-500 flex items-center justify-center gap-1">
   454→                <Edit2 className="w-3.5 h-3.5" /> Edit
   455→              </button>
   456→              <button onClick={() => handleDelete(String((selectedInv as Record<string,unknown>).id))}
   457→                className="rounded-xl bg-red-900/30 px-3 text-red-400 hover:bg-red-900/50 py-2.5">
   458→                <Trash2 className="w-4 h-4" />
   459→              </button>
   460→            </div>
   461→          </div>
   462→        </div>
   463→      )}
   464→    </div>
   465→  );
   466→}
